/* Test driver */
public class Main {
    public static void main(String[] args) {
        RateLimiter l = RateLimiterService.createSlidingWindow(3, 1000);
        int allowed = 0, denied = 0;
        for (int i = 0; i < 5; i++) {
            if (l.allowRequest(new Request("c"))) allowed++; else denied++;
        }
        if (allowed == 3 && denied == 2) System.out.println("OK_LIMIT");
    }
}

