/* Test driver */
public class Main {
    public static void main(String[] args) {
        SlidingWindowLimiter l = new SlidingWindowLimiter(2, 1000);
        long t0 = 10000L;
        boolean r1 = l.allowRequest(new Request("c", t0));
        boolean r2 = l.allowRequest(new Request("c", t0 + 100));
        boolean r3 = l.allowRequest(new Request("c", t0 + 200));
        boolean r4 = l.allowRequest(new Request("c", t0 + 1500));
        if (r1 && r2 && !r3 && r4) System.out.println("OK_SLIDE");
    }
}

